SELECT * FROM api_auth_config

    AND api_id = #{apiId}
    AND (auth_name LIKE CONCAT('%', #{keyword}, '%') OR app_key LIKE CONCAT('%', #{keyword}, '%'))
    AND status = #{status}

ORDER BY created_at DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM api_auth_config

    AND api_id = #{apiId}
    AND (auth_name LIKE CONCAT('%', #{keyword}, '%') OR app_key LIKE CONCAT('%', #{keyword}, '%'))
    AND status = #{status}

SELECT * FROM api_call_log

    AND api_id = #{apiId}
    AND request_path LIKE CONCAT('%', #{apiPath}, '%')
    AND is_success = #{isSuccess}
    AND created_at >= #{startTime}
    AND created_at <= #{endTime}

ORDER BY created_at DESC
LIMIT #{offset}, #{pageSize}

